package ValidationSystem;

use Scalar::Util qw(blessed);

sub new {
    my ($class, %args) = @_;
    my $self = {
        patterns      => {},      # name => compiled regex
        config_file   => $args{config_file} || undef,
        max_pattern_length => $args{max_pattern_length} || 500,
        allowed_flags => qr/^[imsx]*$/,
        error         => undef,
    };
    bless $self, $class;

    if ($self->{config_file}) {
        $self->load_config($self->{config_file});
    }

    return $self;
}

# Safely compile a user-provided regex pattern
# Returns a compiled qr// regex or undef on failure
sub compile_pattern {
    my ($self, $pattern, $flags) = @_;
    $self->{error} = undef;
    $flags //= '';

    # --- Security Validations ---

    # 1. Check that pattern is defined and not empty
    if (!defined $pattern || $pattern eq '') {
        $self->{error} = "Pattern cannot be empty";
        return undef;
    }

    # 2. Enforce maximum pattern length to prevent ReDoS
    if (length($pattern) > $self->{max_pattern_length}) {
        $self->{error} = "Pattern exceeds maximum allowed length of $self->{max_pattern_length}";
        return undef;
    }

    # 3. Validate flags
    if ($flags !~ $self->{allowed_flags}) {
        $self->{error} = "Invalid flags '$flags'. Only i, m, s, x are allowed";
        return undef;
    }

    # 4. Reject patterns containing code execution constructs
    #    Block (?{ }), (??{ }), and other dangerous embedded code patterns
    if ($pattern =~ /\(\s*\?{1,2}\s*\{/ || $pattern =~ /\(\?\?/) {
        $self->{error} = "Pattern contains forbidden embedded code constructs";
        return undef;
    }

    # 5. Block backtick execution and other dangerous Perl interpolation
    if ($pattern =~ /`|\$\{/ ) {
        $self->{error} = "Pattern contains forbidden interpolation constructs";
        return undef;
    }

    # 6. Use eval to safely compile the regex, catching syntax errors
    my $compiled;
    {
        # Use 're' pragma to prevent code execution in regex (Perl 5.10+)
        # no re 'eval' is the default, but be explicit
        no re 'eval';

        $compiled = eval {
            # Compile with qr// using the flag string
            # We build the pattern with (?FLAGS:PATTERN) syntax to avoid
            # string eval and direct /$user_pattern/ injection
            my $full_pattern = "(?$flags:$pattern)" if $flags;
            $full_pattern //= $pattern;
            qr/$full_pattern/;
        };
    }

    if ($@ || !defined $compiled) {
        my $err = $@ || "Unknown compilation error";
        $err =~ s/\s+at\s+\S+\s+line\s+\d+.*//s;  # Clean up error message
        $self->{error} = "Failed to compile pattern: $err";
        return undef;
    }

    return $compiled;
}

# Register a named pattern
sub add_pattern {
    my ($self, $name, $pattern, $flags) = @_;

    if (!defined $name || $name eq '') {
        $self->{error} = "Pattern name cannot be empty";
        return 0;
    }

    my $compiled = $self->compile_pattern($pattern, $flags);
    if (!$compiled) {
        return 0;  # error already set by compile_pattern
    }

    $self->{patterns}{$name} = {
        original => $pattern,
        flags    => $flags // '',
        compiled => $compiled,
    };

    return 1;
}

# Validate a string against a named pattern
sub validate {
    my ($self, $name, $input) = @_;
    $self->{error} = undef;

    if (!exists $self->{patterns}{$name}) {
        $self->{error} = "Unknown pattern name: '$name'";
        return undef;
    }

    if (!defined $input) {
        $self->{error} = "Input cannot be undef";
        return 0;
    }

    my $regex = $self->{patterns}{$name}{compiled};

    # Use alarm to protect against catastrophic backtracking (ReDoS)
    my $matched;
    my $timed_out = 0;

    eval {
        local $SIG{ALRM} = sub { die "TIMEOUT\n" };
        alarm(2);  # 2 second timeout for regex matching
        $matched = ($input =~ $regex) ? 1 : 0;
        alarm(0);
    };

    if ($@) {
        alarm(0);  # Ensure alarm is cleared
        if ($@ =~ /TIMEOUT/) {
            $self->{error} = "Pattern matching timed out (possible ReDoS)";
            return undef;
        }
        $self->{error} = "Error during matching: $@";
        return undef;
    }

    return $matched;
}

# Validate a string against an ad-hoc (unnamed) pattern
sub validate_adhoc {
    my ($self, $pattern, $input, $flags) = @_;
    $self->{error} = undef;

    my $compiled = $self->compile_pattern($pattern, $flags);
    if (!$compiled) {
        return undef;
    }

    if (!defined $input) {
        $self->{error} = "Input cannot be undef";
        return 0;
    }

    my $matched;
    eval {
        local $SIG{ALRM} = sub { die "TIMEOUT\n" };
        alarm(2);
        $matched = ($input =~ $compiled) ? 1 : 0;
        alarm(0);
    };

    if ($@) {
        alarm(0);
        if ($@ =~ /TIMEOUT/) {
            $self->{error} = "Pattern matching timed out (possible ReDoS)";
            return undef;
        }
        $self->{error} = "Error during matching: $@";
        return undef;
    }

    return $matched;
}

# Load patterns from a configuration file
# Format: name<TAB>pattern<TAB>flags (one per line, # comments)
sub load_config {
    my ($self, $file) = @_;
    $self->{error} = undef;

    unless (-f $file && -r $file) {
        $self->{error} = "Config file '$file' not found or not readable";
        return 0;
    }

    open my $fh, '<', $file or do {
        $self->{error} = "Cannot open config file '$file': $!";
        return 0;
    };

    my $count = 0;
    my @errors;

    while (my $line = <$fh>) {
        chomp $line;
        $line =~ s/^\s+|\s+$//g;
        next if $line eq '' || $line =~ /^#/;

        my ($name, $pattern, $flags) = split /\t/, $line, 3;
        $flags //= '';

        if (!defined $name || !defined $pattern) {
            push @errors, "Line $.: Invalid format (expected NAME<TAB>PATTERN[<TAB>FLAGS])";
            next;
        }

        if ($self->add_pattern($name, $pattern, $flags)) {
            $count++;
        } else {
            push @errors, "Line $.: Pattern '$name': $self->{error}";
        }
    }

    close $fh;

    if (@errors) {
        $self->{error} = join("\n", @errors);
    }

    return $count;
}

# Get the last error message
sub error {
    my ($self) = @_;
    return $self->{error};
}

# List all registered pattern names
sub list_patterns {
    my ($self) = @_;
    return sort keys %{$self->{patterns}};
}

# Get info about a named pattern
sub get_pattern_info {
    my ($self, $name) = @_;
    return undef unless exists $self->{patterns}{$name};
    return {
        name     => $name,
        original => $self->{patterns}{$name}{original},
        flags    => $self->{patterns}{$name}{flags},
    };
}

# Remove a named pattern
sub remove_pattern {
    my ($self, $name) = @_;
    if (exists $self->{patterns}{$name}) {
        delete $self->{patterns}{$name};
        return 1;
    }
    return 0;
}

