# Run built-in tests
sub run_tests {
    my ($validator) = @_;

    print "=" x 60, "\n";
    print "Running Validation Tests\n";
    print "=" x 60, "\n\n";

    my @tests = (
        # [pattern_name, input, expected_result, description]
        ['email', 'user@example.com', 1, 'Valid email'],
        ['email', 'invalid-email', 0, 'Invalid email - no @'],
        ['email', 'user@.com', 0, 'Invalid email - no domain'],
        ['email', 'User@Example.COM', 1, 'Valid email - case insensitive'],

        ['phone_us', '(555) 123-4567', 1, 'Valid US phone with parens'],
        ['phone_us', '+1-555-123-4567', 1, 'Valid US phone with country code'],
        ['phone_us', '123', 0, 'Invalid phone - too short'],

        ['ipv4', '192.168.1.1', 1, 'Valid IPv4'],
        ['ipv4', '255.255.255.255', 1, 'Valid IPv4 - max values'],
        ['ipv4', '256.1.1.1', 0, 'Invalid IPv4 - octet > 255'],
        ['ipv4', '1.2.3', 0, 'Invalid IPv4 - missing octet'],

        ['date_iso', '2024-01-15', 1, 'Valid ISO date'],
        ['date_iso', '2024-13-01', 0, 'Invalid date - month 13'],
        ['date_iso', '01-15-2024', 0, 'Invalid date - wrong format'],

        ['username', 'john_doe', 1, 'Valid username'],
        ['username', '1invalid', 0, 'Invalid username - starts with number'],
        ['username', 'ab', 0, 'Invalid username - too short'],

        ['hex_color', '#FF5733', 1, 'Valid hex color - 6 digits'],
        ['hex_color', '#abc', 1, 'Valid hex color - 3 digits'],
        ['hex_color', '#GGHHII', 0, 'Invalid hex color'],

        ['strong_password', 'Str0ng!Pass', 1, 'Valid strong password'],
        ['strong_password', 'weakpass', 0, 'Invalid - no uppercase/digit/special'],
        ['strong_password', 'Short1!', 0, 'Invalid - too short'],
    );

    my ($passed, $failed) = (0, 0);

    for my $test (@tests) {
        my ($name, $input, $expected, $desc) = @$test;
        my $result = $validator->validate($name, $input);

        if (!defined $result) {
            print "  ERROR: $desc - $validator->{error}\n";
            $failed++;
            next;
        }

        my $ok = ($result == $expected);
        if ($ok) {
            $passed++;
            printf "  PASS: %-45s [%s => %s]\n", $desc, $input, $result ? 'match' : 'no match';
        } else {
            $failed++;
            printf "  FAIL: %-45s [%s => got %s, expected %s]\n",
                $desc, $input, $result ? 'match' : 'no match',
                $expected ? 'match' : 'no match';
        }
    }

    print "\n", "-" x 60, "\n";
    printf "Results: %d passed, %d failed, %d total\n\n", $passed, $failed, $passed + $failed;

    return $failed == 0;
}

# Test security measures
sub run_security_tests {
    my ($validator) = @_;

    print "=" x 60, "\n";
    print "Running Security Tests\n";
    print "=" x 60, "\n\n";

    my @security_tests = (
        # [pattern, flags, should_compile, description]
        ['(?{ system("echo pwned") })', '', 0, 'Embedded code execution (?{})'],
        ['(??{ `ls` })', '', 0, 'Deferred code execution (?{})'],
        ['(?{print "hi"})', '', 0, 'Embedded print statement'],
        ['${\\system("ls")}', '', 0, 'Variable interpolation attack'],
        ['a' x 600, '', 0, 'Excessively long pattern'],
        ['^valid$', 'gimsx', 0, 'Invalid flag g'],
        ['^valid$', 'e', 0, 'Dangerous eval flag e'],
        ['^[a-z]+$', 'i', 1, 'Normal pattern with valid flag'],
        ['', '', 0, 'Empty pattern'],
        ['^\\d{3}$', '', 1, 'Simple digit pattern'],
        ['[invalid', '', 0, 'Unbalanced bracket (syntax error)'],
    );

    my ($passed, $failed) = (0, 0);

    for my $test (@security_tests) {
        my ($pattern, $flags, $should_compile, $desc) = @$test;
        my $compiled = $validator->compile_pattern($pattern, $flags);
        my $did_compile = defined $compiled ? 1 : 0;

        my $ok = ($did_compile == $should_compile);
        if ($ok) {
            $passed++;
            printf "  PASS: %-50s [%s]\n", $desc,
                $did_compile ? 'compiled OK' : "blocked: " . ($validator->error // 'unknown');
        } else {
            $failed++;
            printf "  FAIL: %-50s [expected %s, got %s]\n", $desc,
                $should_compile ? 'compile' : 'block',
                $did_compile ? 'compiled' : 'blocked';
            if ($validator->error) {
                printf "        Error: %s\n", $validator->error;
            }
        }
    }

    print "\n", "-" x 60, "\n";
    printf "Security Results: %d passed, %d failed, %d total\n\n", $passed, $failed, $passed + $failed;

    return $failed == 0;
}

# Interactive mode
sub interactive_mode {
    my ($validator) = @_;

    print "=" x 60, "\n";
    print "Interactive Validation Mode\n";
    print "=" x 60, "\n";
    print "\nCommands:\n";
    print "  list              - List all registered patterns\n";
    print "  add <name>        - Add a new named pattern\n";
    print "  remove <name>     - Remove a named pattern\n";
    print "  test <name>       - Test input against a named pattern\n";
    print "  adhoc             - Test input against an ad-hoc pattern\n";
    print "  info <name>       - Show pattern details\n";
    print "  quit              - Exit\n\n";

    while (1) {
        print "> ";
        my $line = <STDIN>;
        last unless defined $line;
        chomp $line;
        $line =~ s/^\s+|\s+$//g;
        next if $line eq '';

        my ($cmd, @args) = split /\s+/, $line, 2;
        $cmd = lc($cmd // '');

        if ($cmd eq 'quit' || $cmd eq 'exit' || $cmd eq 'q') {
            print "Goodbye!\n";
            last;
        }
        elsif ($cmd eq 'list') {
            my @names = $validator->list_patterns();
            if (@names) {
                print "Registered patterns:\n";
                for my $name (@names) {
                    my $info = $validator->get_pattern_info($name);
                    printf "  %-20s /%s/%s\n", $name, $info->{original}, $info->{flags};
                }
            } else {
                print "No patterns registered.\n";
            }
        }
        elsif ($cmd eq 'add') {
            my $name = $args[0];
            unless ($name) {
                print "Pattern name: ";
                $name = <STDIN>;
                chomp $name if defined $name;
            }
            print "Regex pattern: ";
            my $pattern = <STDIN>;
            chomp $pattern if defined $pattern;
            print "Flags (imsx, or empty): ";
            my $flags = <STDIN>;
            chomp $flags if defined $flags;
            $flags //= '';

            if ($validator->add_pattern($name, $pattern, $flags)) {
                print "Pattern '$name' added successfully.\n";
            } else {
                print "Error: " . $validator->error . "\n";
            }
        }
        elsif ($cmd eq 'remove') {
            my $name = $args[0];
            unless ($name) {
                print "Pattern name: ";
                $name = <STDIN>;
                chomp $name if defined $name;
            }
            if ($validator->remove_pattern($name)) {
                print "Pattern '$name' removed.\n";
            } else {
                print "Pattern '$name' not found.\n";
            }
        }
        elsif ($cmd eq 'test') {
            my $name = $args[0];
            unless ($name) {
                print "Pattern name: ";
                $name = <STDIN>;
                chomp $name if defined $name;
            }
            print "Input string: ";
            my $input = <STDIN>;
            chomp $input if defined $input;

            my $result = $validator->validate($name, $input);
            if (!defined $result) {
                print "Error: " . $validator->error . "\n";
            } elsif ($result) {
                print "MATCH - Input is valid.\n";
            } else {
                print "NO MATCH - Input does not match pattern.\n";
            }
        }
        elsif ($cmd eq 'adhoc') {
            print "Regex pattern: ";
            my $pattern = <STDIN>;
            chomp $pattern if defined $pattern;
            print "Flags (imsx, or empty): ";
            my $flags = <STDIN>;
            chomp $flags if defined $flags;
            $flags //= '';
            print "Input string: ";
            my $input = <STDIN>;
            chomp $input if defined $input;

            my $result = $validator->validate_adhoc($pattern, $input, $flags);
            if (!defined $result) {
                print "Error: " . $validator->error . "\n";
            } elsif ($result) {
                print "MATCH - Input is valid.\n";
            } else {
                print "NO MATCH - Input does not match pattern.\n";
            }
        }
        elsif ($cmd eq 'info') {
            my $name = $args[0];
            unless ($name) {
                print "Pattern name: ";
                $name = <STDIN>;
                chomp $name if defined $name;
            }
            my $info = $validator->get_pattern_info($name);
            if ($info) {
                printf "Name:    %s\n", $info->{name};
                printf "Pattern: /%s/\n", $info->{original};
                printf "Flags:   %s\n", $info->{flags} || '(none)';
            } else {
                print "Pattern '$name' not found.\n";
            }
        }
        else {
            print "Unknown command: '$cmd'. Type 'quit' to exit.\n";
        }
        print "\n";
    }
}

# =============================================================================
# Main entry point
# =============================================================================

sub main {
    my $mode = $ARGV[0] // 'all';

    print "\n";
    print "*" x 60, "\n";
    print "* Flexible Input Validation System                        *\n";
    print "* Using Safely Compiled Dynamic Regular Expressions       *\n";
    print "*" x 60, "\n\n";

    # Create and initialize the validator
    my $config_file = create_sample_config();
    my $validator = ValidationSystem->new(
        config_file        => $config_file,
        max_pattern_length => 500,
    );

    # Show loaded patterns
    my @patterns = $validator->list_patterns();
    printf "Loaded %d patterns from config.\n", scalar @patterns;
    if ($validator->error) {
        print "Config warnings:\n$validator->{error}\n";
    }
    print "\n";

    if ($mode eq 'test' || $mode eq 'all') {
        run_tests($validator);
        run_security_tests($validator);
    }

    if ($mode eq 'interactive' || $mode eq 'all') {
        if (-t STDIN) {
            interactive_mode($validator);
        } elsif ($mode eq 'interactive') {
            interactive_mode($validator);
        }
    }

    # Cleanup
    unlink $config_file if -f $config_file;
}

main();